// -- page number format (§17.6.12) ------------------------------------------

/// ISO 29500-1 §17.6.12: pgNumType attributes (fmt, start) should be captured
/// in SectionProperties.
///
/// The fixture has pgNumType with fmt=lowerRoman, start=3.
#[test]
fn spec_page_number_format_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "page-number-format");

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one paragraph with section properties"
    );

    let props = section_props[0];
    let pg = props
        .page_number_type
        .as_ref()
        .expect("should have page number type");
    assert_eq!(pg.fmt.as_deref(), Some("lowerRoman"));
    assert_eq!(pg.start, Some(3));
}
